const GEO_URL = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-50m.json";

/* European countries to display */
const EUROPE_NAMES = [
  "Albania","Andorra","Austria","Belarus","Belgium","Bosnia and Herz.",
  "Bulgaria","Croatia","Cyprus","Czech Rep.","Czechia","Denmark","Estonia",
  "Finland","France","Germany","Greece","Hungary","Iceland","Ireland",
  "Italy","Kosovo","Latvia","Lithuania","Luxembourg","Malta","Moldova",
  "Montenegro","Netherlands","North Macedonia","Macedonia","Norway","Poland","Portugal",
  "Romania","Serbia","Slovakia","Slovenia","Spain","Sweden",
  "Switzerland","Ukraine","United Kingdom","Turkey",
  "Greenland","Georgia","San Marino",
];

const TOTAL_MEMBERS = Object.values(MEMBER_DATA).reduce((a, b) => a + b, 0);

function getPercent(count) {
  if (!count || count === 0) return 0;
  return (count / TOTAL_MEMBERS) * 100;
}

function getColor(count) {
  if (!count || count === 0) return "#fafafa";
  const pct = getPercent(count);
  const intensity = Math.min(pct / 25, 1); // 25%+ = full intensity
  const r = Math.round(230 - intensity * 190);
  const g = Math.round(230 - intensity * 170);
  const b = 220;
  return `rgb(${r}, ${g}, ${b})`;
}


