/* Countries that should be linked (hover one = highlight both) */
const LINKED = {
  Greenland: "Denmark",
  Denmark: "Denmark",
  Crimea: "Ukraine",
  Ukraine: "Ukraine",
};

/* Tooltip labels */
const TOOLTIP_LABELS = {
  Greenland: "Greenland (Denmark)",
  Crimea: "Crimea (Ukraine)",
};

function getDisplayName(name) {
  return LINKED[name] || name;
}

function getTooltipLabel(name) {
  return TOOLTIP_LABELS[name] || name;
}

function isHighlighted(name, hovered) {
  if (!hovered) return false;
  const hoveredGroup = getDisplayName(hovered);
  const nameGroup = getDisplayName(name);
  return hoveredGroup === nameGroup;
}

/* Scale Crimea polygon down slightly toward its centroid */
function shrinkPolygon(coords, factor) {
  const cx = coords.reduce((s, c) => s + c[0], 0) / coords.length;
  const cy = coords.reduce((s, c) => s + c[1], 0) / coords.length;
  return coords.map(([lon, lat]) => [
    cx + (lon - cx) * factor,
    cy + (lat - cy) * factor,
  ]);
}

const shrunkCoords = shrinkPolygon(CRIMEA_GEO.features[0].geometry.coordinates[0], 0.80);
const shiftedCoords = shrunkCoords.map(([lon, lat]) => [lon, lat + 0.04]);
const shrunkCrimea = {
  type: "Polygon",
  coordinates: [shiftedCoords],
};

/* Projection matching ComposableMap config */
/* Projection for Crimea — matches ComposableMap config exactly */
const crimeaProjection = geoAzimuthalEqualArea()
  .rotate([-15, -52, 0])
  .center([1, 0])
  .scale(580)
  .translate([800 / 2, 480 / 2]);

const crimeaPathGen = geoPath().projection(crimeaProjection);
const crimeaD = crimeaPathGen(shrunkCrimea);

function CrimeaPath({ hovered, setHovered }) {
  const count = MEMBER_DATA["Ukraine"] || 0;
  const highlighted = isHighlighted("Crimea", hovered);
  return (
    <path
      d={crimeaD}
      fill={highlighted ? (count > 0 ? getColor(count) : "#e8e8e8") : getColor(count)}
      stroke={highlighted ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)"}
      strokeWidth={highlighted ? 1.5 : 0.75}
      style={{ transition: "fill 0.05s ease, stroke 0.05s ease", cursor: "pointer", outline: "none" }}
      onMouseEnter={() => setHovered("Ukraine")}
      onMouseLeave={() => setHovered(null)}
    />
  );
}

const MapChart = memo(function MapChart() {
  const [hovered, setHovered] = useState(null);

  return (
    <div className="relative">
      <ComposableMap
        projection="geoAzimuthalEqualArea"
        projectionConfig={{
          rotate: [-15, -52, 0],
          center: [1, 0],
          scale: 580,
        }}
        width={800}
        height={480}
        style={{ width: "100%", height: "auto", display: "block", margin: "0 auto" }}
      >
        <Geographies geography={GEO_URL}>
          {({ geographies }) =>
            geographies
              .filter((geo) => EUROPE_NAMES.includes(geo.properties.name))
              .map((geo) => {
                const name = geo.properties.name;
                const displayName = getDisplayName(name);
                const count = MEMBER_DATA[name] || MEMBER_DATA[displayName] || 0;
                const highlighted = isHighlighted(name, hovered);
                return (
                  <Geography
                    key={geo.rsmKey}
                    geography={geo}
                    onMouseEnter={() => setHovered(name)}
                    onMouseLeave={() => setHovered(null)}
                    style={{
                      default: {
                        fill: highlighted
                          ? (count > 0 ? getColor(count) : "#e8e8e8")
                          : getColor(count),
                        stroke: highlighted ? "rgba(0,0,0,0.5)" : "rgba(0,0,0,0.2)",
                        strokeWidth: highlighted ? 1.5 : 0.75,
                        transition: "all 0.3s ease",
                        outline: "none",
                        cursor: "pointer",
                      },
                      hover: {
                        fill: count > 0 ? getColor(count) : "#e8e8e8",
                        stroke: "rgba(0,0,0,0.5)",
                        strokeWidth: 1.5,
                        outline: "none",
                        cursor: "pointer",
                      },
                      pressed: {
                        outline: "none",
                      },
                    }}
                  />
                );
              })
          }
        </Geographies>

        {/* Crimea as part of Ukraine */}
        <CrimeaPath hovered={hovered} setHovered={setHovered} />
      </ComposableMap>

      {/* Tooltip */}
      {hovered && (
        <div
          className="absolute top-4 left-1/2 -translate-x-1/2 bg-black/85 text-white px-4 py-2 rounded-sm pointer-events-none"
          style={{ zIndex: 10 }}
        >
          <span
            className="text-xs tracking-[0.15em] uppercase font-sans"
            style={{ fontWeight: 400 }}
          >
            {getTooltipLabel(hovered)}
          </span>
        </div>
      )}
    </div>
  );
});

