/* ───────────────────────── helpers ───────────────────────── */

function useTypewriter(text, speed = 70, startDelay = 1200) {
  const [displayed, setDisplayed] = useState("");
  const [done, setDone] = useState(false);
  useEffect(() => {
    let i = 0;
    const timeout = setTimeout(() => {
      const interval = setInterval(() => {
        i++;
        setDisplayed(text.slice(0, i));
        if (i >= text.length) {
          clearInterval(interval);
          setDone(true);
        }
      }, speed);
      return () => clearInterval(interval);
    }, startDelay);
    return () => clearTimeout(timeout);
  }, [text, speed, startDelay]);
  return { displayed, done };
}

/* ──────────────── background star field (persistent) ──────────────── */

function StarField() {
  const stars = Array.from({ length: 12 }, (_, i) => {
    const angle = (i / 12) * Math.PI * 2 - Math.PI / 2;
    const radius = 34;
    return {
      x: 50 + radius * Math.cos(angle),
      y: 50 + radius * Math.sin(angle),
      delay: i * 0.15,
    };
  });

  return (
    <div className="absolute inset-0 flex items-center justify-center pointer-events-none overflow-hidden">
      <motion.div
        className="relative"
        style={{ width: "min(700px, 90vw)", height: "min(700px, 90vw)" }}
        animate={{ rotate: 360 }}
        transition={{ duration: 240, repeat: Infinity, ease: "linear" }}
      >
        {stars.map((s, i) => (
          <motion.div
            key={i}
            className="absolute"
            style={{ left: `${s.x}%`, top: `${s.y}%`, transform: "translate(-50%,-50%)" }}
            animate={{ opacity: [0.12, 0.28, 0.12], scale: [0.9, 1.1, 0.9] }}
            transition={{
              duration: 4,
              repeat: Infinity,
              delay: s.delay,
              ease: "easeInOut",
            }}
          >
            <Star
              size={18}
              className="text-black"
              fill="rgba(0,0,0,0.08)"
              strokeWidth={1}
            />
          </motion.div>
        ))}
      </motion.div>
    </div>
  );
}

/* ──────────────────── intro: EU flag animation ──────────────────── */

function IntroAnimation({ onComplete }) {
  const [phase, setPhase] = useState("gather"); // gather -> fade -> done

  useEffect(() => {
    const t1 = setTimeout(() => setPhase("fade"), 2400);
    const t2 = setTimeout(() => {
      setPhase("done");
      onComplete();
    }, 3600);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [onComplete]);

  const stars = Array.from({ length: 12 }, (_, i) => {
    const angle = (i / 12) * Math.PI * 2 - Math.PI / 2;
    const r = 100;
    return {
      cx: r * Math.cos(angle),
      cy: r * Math.sin(angle),
      i,
    };
  });

  return (
    <AnimatePresence>
      {phase !== "done" && (
        <motion.div
          className="fixed inset-0 z-[100] bg-white flex flex-col items-center justify-center"
          exit={{ opacity: 0 }}
          transition={{ duration: 1.0 }}
        >
          {/* Star circle — parent rotates during gather, holds still during fade */}
          <motion.div
            className="relative"
            style={{ width: 240, height: 240 }}
            animate={{ rotate: phase === "gather" ? 360 : 360 }}
            transition={{ duration: 2.4, ease: [0.25, 0.1, 0.25, 1] }}
          >
            {stars.map((s) => (
              <motion.div
                key={s.i}
                className="absolute"
                style={{ left: "50%", top: "50%" }}
                initial={{ x: s.cx, y: s.cy, opacity: 0, scale: 0 }}
                animate={
                  phase === "gather"
                    ? { x: s.cx, y: s.cy, opacity: 1, scale: 1 }
                    : { x: s.cx, y: s.cy, opacity: 0, scale: 0.8 }
                }
                transition={
                  phase === "gather"
                    ? { duration: 0.8, delay: s.i * 0.06, ease: "easeOut" }
                    : { duration: 1.2, ease: "easeInOut" }
                }
              >
                <Star
                  size={16}
                  className="text-black"
                  fill="black"
                  strokeWidth={0}
                  style={{ transform: "translate(-50%, -50%)" }}
                />
              </motion.div>
            ))}
          </motion.div>

          {/* Title below the star circle */}
          <motion.p
            className="font-serif text-black/40 text-2xl sm:text-3xl tracking-[0.3em] uppercase mt-10"
            initial={{ opacity: 0, y: 15 }}
            animate={
              phase === "gather"
                ? { opacity: 1, y: 0 }
                : { opacity: 0, y: -10 }
            }
            transition={{ duration: 0.8, delay: phase === "gather" ? 1.2 : 0 }}
          >
            First Domino
          </motion.p>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

